/*!
 * Prism.js Simplified Syntax Highlighter
 */

window.Prism = (() => {

    function highlightAll() {

        const blocks =
            document.querySelectorAll(
                'pre code'
            );

        blocks.forEach(block => {

            const original =
                block.innerHTML;

            let highlighted =
                original;

            highlighted =
                highlighted.replace(
                    /\b(function|return|if|else|for|while|class|const|let|var)\b/g,
                    '<span class="token keyword">$1</span>'
                );

            highlighted =
                highlighted.replace(
                    /("[^"]*"|'[^']*')/g,
                    '<span class="token string">$1</span>'
                );

            highlighted =
                highlighted.replace(
                    /\b(\d+)\b/g,
                    '<span class="token number">$1</span>'
                );

            block.innerHTML =
                highlighted;
        });
    }

    return {
        highlightAll
    };
})();